import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { AuthProvider, useAuth } from "./context/AuthContext";
import Login from "./pages/Login";
import Register from "./pages/Register";

/**
 * ProtectedRoute — Guards routes that require authentication.
 *
 * How it works:
 *  - If user is NOT logged in → redirect to /login
 *  - If a requiredRole is specified and user's role doesn't match → redirect to /login
 *  - Otherwise → render the child component
 *
 * Usage:
 *  <ProtectedRoute requiredRole="ADMIN"><AdminDashboard /></ProtectedRoute>
 *  <ProtectedRoute><VoterDashboard /></ProtectedRoute>
 */
const ProtectedRoute = ({ children, requiredRole }) => {
  const { isAuthenticated, user } = useAuth();

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />;
  }

  if (requiredRole && user?.role !== requiredRole) {
    return <Navigate to="/login" replace />;
  }

  return children;
};

/**
 * AppRoutes — Defines all routes in the application.
 *
 * Route structure:
 *  /           → redirect to /login
 *  /login      → Login page (public)
 *  /register   → Register page (public)
 *  /voter/dashboard  → Voter dashboard (protected, VOTER role) — Module 3
 *  /admin/dashboard  → Admin dashboard (protected, ADMIN role) — Module 2
 *
 * Placeholder components are used for dashboards until those modules are built.
 */
const AppRoutes = () => {
  return (
    <Routes>
      {/* Default route — redirect to login */}
      <Route path="/" element={<Navigate to="/login" replace />} />

      {/* Public routes — accessible without a token */}
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />

      {/* Protected: Voter Dashboard — will be replaced in Module 3 */}
      <Route
        path="/voter/dashboard"
        element={
          <ProtectedRoute requiredRole="VOTER">
            <VoterDashboardPlaceholder />
          </ProtectedRoute>
        }
      />

      {/* Protected: Admin Dashboard — will be replaced in Module 2 */}
      <Route
        path="/admin/dashboard"
        element={
          <ProtectedRoute requiredRole="ADMIN">
            <AdminDashboardPlaceholder />
          </ProtectedRoute>
        }
      />

      {/* Catch-all — redirect unknown routes to login */}
      <Route path="*" element={<Navigate to="/login" replace />} />
    </Routes>
  );
};

// ── Temporary Placeholder Components (replaced in later modules) ───────────
const VoterDashboardPlaceholder = () => {
  const { user, logout } = useAuth();
  return (
    <div style={placeholderStyle}>
      <h2>👤 Welcome, {user?.fullName}!</h2>
      <p>Role: {user?.role} | Email: {user?.email}</p>
      <p style={{ color: "#e67e22" }}>
        ⏳ Your account is pending admin verification before you can vote.
      </p>
      <button onClick={logout} style={logoutBtnStyle}>Logout</button>
    </div>
  );
};

const AdminDashboardPlaceholder = () => {
  const { user, logout } = useAuth();
  return (
    <div style={placeholderStyle}>
      <h2>🔧 Admin Panel — {user?.fullName}</h2>
      <p>Role: {user?.role} | Email: {user?.email}</p>
      <p style={{ color: "#27ae60" }}>✅ Full admin dashboard coming in Module 2.</p>
      <button onClick={logout} style={logoutBtnStyle}>Logout</button>
    </div>
  );
};

const placeholderStyle = {
  padding: "3rem",
  fontFamily: "'Segoe UI', sans-serif",
  textAlign: "center",
  maxWidth: "600px",
  margin: "4rem auto",
};

const logoutBtnStyle = {
  marginTop: "1.5rem",
  padding: "0.6rem 1.5rem",
  backgroundColor: "#e53e3e",
  color: "white",
  border: "none",
  borderRadius: "8px",
  cursor: "pointer",
  fontSize: "0.95rem",
};

/**
 * App — Root component.
 * Wraps everything in:
 *  1. BrowserRouter — enables client-side routing
 *  2. AuthProvider  — provides global auth state to all components
 */
const App = () => {
  return (
    <BrowserRouter>
      <AuthProvider>
        <AppRoutes />
      </AuthProvider>
    </BrowserRouter>
  );
};

export default App;
